mapper.select:
SELECT t.tcm_tar_id AS tcmTarId, t.gene_entrez_id AS geneEntrezId, COALESCE(t.symbol, '') AS symbol, COALESCE(NULLIF(TRIM(t.uniprot_id), '#N/A'), NULL) AS uniprotId, COALESCE(t.ensembl_id, '') AS ensemblId, COALESCE(t.description, '') AS description, COALESCE(t.type_of_gene, '') AS typeOfGene FROM pathway_target_rel ptr INNER JOIN targets t ON ptr.tcm_tar_id = t.tcm_tar_id WHERE ptr.pathway_id = #{pathwayId}
AND ( t.symbol LIKE CONCAT('%', #{keyword}, '%') OR t.description LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY t.symbol

SELECT c.inchikey, c.molecular_formula AS molecularFormula, c.molecular_weight AS molecularWeight, c.pubchem_cid AS pubchemCid, COUNT(DISTINCT ct.tcm_tar_id) AS targetCount FROM pathway_target_rel ptr INNER JOIN compound_target_rel ct ON ptr.tcm_tar_id = ct.tcm_tar_id INNER JOIN tcm_compounds c ON ct.inchikey = c.inchikey WHERE ptr.pathway_id = #{pathwayId}
AND ( c.inchikey LIKE CONCAT(#{keyword}, '%') OR c.molecular_formula LIKE CONCAT(#{keyword}, '%') )
GROUP BY c.inchikey, c.molecular_formula, c.molecular_weight, c.pubchem_cid ORDER BY targetCount DESC

SELECT h.tcm_herb_id AS tcmHerbId, h.herb_name_zh AS herbNameZh, h.pinyin_name AS pinyinName, COUNT(DISTINCT ct.inchikey) AS compoundCount, COUNT(DISTINCT ptr.tcm_tar_id) AS targetCount FROM pathway_target_rel ptr INNER JOIN compound_target_rel ct ON ptr.tcm_tar_id = ct.tcm_tar_id INNER JOIN herb_compound_rel hcr ON ct.inchikey = hcr.inchikey INNER JOIN core_tcm_herbs h ON hcr.tcm_herb_id = h.tcm_herb_id WHERE ptr.pathway_id = #{pathwayId}
AND ( h.herb_name_zh LIKE CONCAT(#{keyword}, '%') OR h.pinyin_name LIKE CONCAT(#{keyword}, '%') )
GROUP BY h.tcm_herb_id ORDER BY targetCount DESC, compoundCount DESC
